module RefModule (
    input clk,
    input rst,
    input en,
    input [31:0] d,
    output reg [31:0] q
);
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
        if (rst)
            q <= 32'b0;
        else if (en)
            q <= d;
    end
endmodule
